var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"날 이런 데로 부르다니, 너도 많이 심심했던 모양이구만.","JPN":"わしをこんな場所に呼ぶなんて、お主も暇だったようじゃのう。","ENG":"Guess you were also pretty bored to call me over.","TWN":"竟然把我找來這種地方，看來你也蠻無聊的嘛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"할 일 없으면 같이 공방에 가서 풀무질이라도 거드는 게 어떠냐? 한 번쯤 나보다 오래 산 인간을 제자로 삼는 것도 각별한 즐거움이 될 것 같은데.","JPN":"やることがなければ一緒に工房に行ってふいごを踏んでくるのはどうじゃ？　一度くらいはわしより長生きした人間を弟子にするのも格別な楽しさを味わえると思うのじゃが。","ENG":"If you have nothing to do, how about helping me with the bellows in the workshop? I think having a human apprentice who has outlived me would be fun.","TWN":"無聊的話就和我一起去工坊拉風箱吧？收一個活得比我還久的人來當徒弟似乎也別有一番樂趣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"응…? 내가 너보다 어린 걸 알면서, 왜 여태 웃어른 행세를 한 거냐고?","JPN":"うん…？　わしが年下であると知っていながら、なぜ目上のように振る舞っているのかって？","ENG":"Hmm...? Why did I pretend to be older than you, knowing you were older than me?","TWN":"嗯…？明明知道你比我大，怎麼講話還這麼不客氣？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"듣고 보니 그렇군. 연합이나 관리국엔 늘 나보다 어린 녀석들뿐이라 잠시 잊고 있었어.","JPN":"確かに。連盟や管理局にはいつもわしより若い者ばかりじゃから、すっかり忘れておった。","ENG":"Come to think of it, you're right. I guess I forgot because the Family Alliance and Administration are full of young folks.","TWN":"聽你這麼一說好像是欸？因為不管是在家族還是管理局裡，大家都比我小，所以我才一時忘記原來你比我年長。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"좋다. 그럼 나도 간만에 간 쓸개 다 내놓고 아가씨처럼 아양이나 떨어볼까?","JPN":"よかろう。ならばわしも何もかも捨てて、若いおなごのように愛嬌を振る舞ってみるか？","ENG":"Okay. Then maybe I'll set aside my embarrassment and act all cute like a young lady to you?","TWN":"好吧，那我就久違地放膽學年輕姑娘們說話吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"오라버니- 부디 그 늠름한 팔을 걷어붙여, 소녀와 함께 멋진 칼을 만들어보지 않으시겠사와요?","JPN":"兄上～どうかそのたくましい腕で、私と一緒に素敵な刀を作りませんか？","ENG":"Mister... Why don't you roll up your sleeves to show off those dashing arms and join me in making an exquisite sword? Please, Mister.","TWN":"哥哥，可以舉起你強壯的手臂，和小姑娘我一起打造一把帥氣的劍嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"이전 말투가 더 낫다고? 젊은 애들은 이런 말투를 더 선호하던데, 취향 한 번 까다롭구만.","JPN":"前の口調のほうがいいじゃと？　若者はこんな口調を好むと聞いたが、なかなか好みがうるさいのう。","ENG":"You like my original tone better? The young ones seemed to prefer this one. Guess you're a picky one.","TWN":"還是用原本的語氣說話比較好嗎？年輕人都喜歡這種語調說，你還真難伺候。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"하지만 그 칠색팔색하는 모습을 보니 오히려 마음에 든다. 나중에 또 써먹어볼까?","JPN":"だがその嫌がる姿を見て、むしろ気に入いったぞ。あとでまたやってやろうか？","ENG":"But I like seeing your astonished face. Perhaps I will use it on you again later.","TWN":"不過看你臉色鐵青也是蠻有趣的，下次再跟你玩玩吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"걱정 마라. 놀리긴 놀려도, 억지로 쇠질을 시키진 않을 테니.","JPN":"心配するでない。無理やり鍛冶屋の仕事をさせたりはしないから。","ENG":"Don't worry. I might tease you, but I won't force you to strike the anvil with a hammer.","TWN":"放心，玩歸玩，我不會硬逼你去打鐵的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"널 대장간에 들이기엔 그 그릇이 너무 크다.","JPN":"お主を鍛冶屋に置いておくには、器が大きすぎる。","ENG":"You have more important things to do than work at a blacksmith shop.","TWN":"因為你的塊頭太大，進不去工坊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"강산이 수백 번 변해도 따라잡지 못하는 것이 연륜이란 게지. 사람을 이끄는 데엔 나보다 도가 텄으니 애초에 내가 다른 재능을 찾아줄 필요도 없다.","JPN":"風景が数百回と変わろうと、追いつけられないのが年の功というものじゃ。人を率いるところではわしより悟りを得ているのじゃから、そもそもわしが別にお主の才能を見抜く必要もなかろう。","ENG":"You have incomparable years of experience. And you appear to have a gift for leadership, so there is no need for me to find you another talent.","TWN":"無論山色如何改變，也無法追上歲月的痕跡。你在領導人方面比我還出色，所以你不需要其他才能來證明你自己。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"모두가 그 사실을 인정하기 때문에, 네 멋대로 이름 지은 고르디우스란 매듭에 코가 꿰이고서도… 그 모든 일을 겪고서도… 널 계속 믿고 따르는 것이다.","JPN":"みんながその事実を認めるがゆえ、お主が勝手に名付けたゴルディウスという縄に縛られても…あんな目に遭っても…お主のことをずっと信じて従っているのじゃ。","ENG":"Everyone acknowledges this. That's why I still continue to trust and follow you after all I've been through. It's been like this since you named us Gordias on your own.","TWN":"大家也都這麼認為，因此就算你因為哥帝爾斯的事被人抓住弱點…在經歷這所有的事後…大家還是願意持續跟隨你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"그러니 앞으로도 잘 부탁하마. 관리자.","JPN":"だからこれからもよろしく頼むぞ。管理者。","ENG":"I look forward to being with you in the future, Administrator.","TWN":"所以之後還請多指教囉，管理者。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CRAFTER_NANAHARA_NULL_NULL","text":{"KOREA":"아니면… 관리자 오라버니가 더 좋으냐?","JPN":"じゃなくて…管理者の兄上と呼んだほうがよろしいか？","ENG":"Or... would you prefer that I call you \\"Mister\\"?","TWN":"還是…你要我叫你管理者哥哥？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRAFTER_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};